  `star_usable` int(11) NOT NULL DEFAULT '0' COMMENT 'пҪ»й„ҷ?пҪЎпҪҙпҫүпҫҮпҫ‘ star (=пҪ»й„ҷ?пҫҸпҪ°?пҪіпҪІпҫҖпҪә star)',
  `survival_best` smallint(6) NOT NULL DEFAULT '0' COMMENT 'пҪјпҪӯпҪ№пҫҷпҫҖпҫҢпҪ№??и ўпҪЎпҪјпҪӯ пҫ…пҪ¬пҪёпҪ®пҪҫ?пҫ‘ пҫғпҫ–пҪҙ?пҪҪпҪәпҫ…пҫ—пҫҖпҫҢпҫҒ??пҪЈ',
