  `slot_list` blob NOT NULL COMMENT 'пҪҪпҪҪпҪ·пҫ” пҪёпҪ®пҪҪпҪәпҫҶпҪ®',
  `buy_item_list` blob NOT NULL COMMENT 'пҪҫ?пҫ—пҪ·пҪ№пҫҖпҫҢпҪө?пҪ»?пҪЎпҪҝпҪЎпҪјпҪӯ пҪұпҪёпҪёпҫ…пҫҮпҫ‘ пҪҫпҫҶпҫҖпҫҢпҫ…пҫӣ пҪёпҪ®пҪҪпҪәпҫҶпҪ®',
  `reward_list` blob NOT NULL COMMENT 'пҪҫ??пҪәпҪёпҪ»?пҪёпҪ®пҪҪпҪәпҫҶпҪ®',
