INSERT INTO `log_query_ref` VALUES ('*B8583582EDEAD9C',1,'seLect slang from slang_list_name'),('*D97DCEA3E7673B2',2,'seLect @@identity'),('*1A3E38BFC88DE52',3,'seLect slang from slang_list'),('*1682A2ECA954997',4,'seLect m_id, level from gm_manifest'),('*C0D155921D7BA43',5,'seLect level, exp from monster_reward_ref'),('*89D927522E9A6A5',6,'upDate login_account_%d set login_status=0 where m_channel_no=%d'),('*EC2BF0BDCB96F85',7,'seLect event_id, event_name from dnf_event_info'),('*9D85D7D192A29BF',8,'seLect event_type, parameter1, parameter2 from dnf_event_log where end_time = 0 and server_id in (0,%d) and unix_timestamp() >= start_time order by start_time'),('*0049E86CEB03667',9,'seLect guild_id, guild_name, lev , power_side, guild_agit_flag from guild_info where expire_flag = 0 and server_id = %d'),('*B228608CBA743A8',10,'seLect * from in_game_ad where visible = 1'),('*B36C615E3CBDD69',11,'seLect item_id,upgrade,average_price from auction_average_price'),('*EB71B0B0D318301',12,'seLect ip,start_ip,end_ip from auto_punish_blackip_info where apply_flag=1 limit %d'),('*861800114BD642A',13,'seLect hack_type,cnt,etc,hack_sub_type,hack_sub_cnt,apply_flag, ip_cnt from auto_punish_hack_info where apply_flag > 0'),('*B95FCD30ACC980F',14,'seLect hack_type,value from hack_cleanpad_ratio_info'),('*6863ACC34007C7E',15,'seLect ip, type, m_id_cnt, unix_timestamp(start_time), unix_timestamp(end_time) from ip_monitor_punish ORDER BY start_time ASC'),('*CF8023F3B73003B',16,'seLect charac_no from charac_tower_despair_apc limit 10'),('*ED663684CAD3B3B',17,'seLect category, restrict_code, restrict_value from dnf_restrict_state where server_group=%d'),('*BDC65252D0C038C',18,'seLect country_code from geo_allow_country where server_group = %d'),('*3CB80E282B6B059',19,'inSert into game_channel (gc_no,gc_now,gc_ip,gc_port,gc_max,gc_game,gc_channel,gc_ch_group,gc_channeltype,gc_up_time, gc_type) values(%d,0,\'%s\',%d,%d,%d,\'%s\',%d,\'%s\',now(),%d)'),('*A28EF36E2AA4850',20,'inSert into channel_occ_info (gc_no, age, occ_num) values %s'),('*0340E761AD8683E',21,'upDate channel_occ_info set occ_num = 0 where gc_no = %d'),('*8CA61ABBABFC1AE',22,'seLect kind, message_index, charac_name, message, unix_timestamp(update_time) from event_server_message where server_info=%d and (channel_no=%d or channel_no=0)'),('*668641EC066211D',23,' seLect category, code, state from server_state_info where end_time >= now()'),('*2B4EF13CA44D8B5',24,'inSert into log_response_time_%s(channel_no,occ_time,packet_id,packet_count,total_response_time,avg_response_time) values%s'),('*A430F68539EA10B',25,'seLect optimum_gold_supply, over_gold from auto_market_condition_ctrl limit 1'),('*BDD5075C427A5B1',26,'seLect total_gold, auction_gold, optimum_gold_supply, over_gold, gold_phase, item_phase, durability_phase from auto_market_condition_ctrl_daily where occ_time >= DATE_SUB(CURDATE(), INTERVAL 1 DAY) order by occ_time limit 2'),('*FE9E568D694D9BE',27,'upDate client_down set occ_count = occ_count+%d where occ_date = cast(now() as date)'),('*D9FDAFDD29F1CDA',28,'inSert ignore into dnf_restrict_state (server_group , category , restrict_code , restrict_value , mod_date , reg_date) values(%d, %d, %d, \'%d\', now(), now())'),('*AEA3E6A45377B58',29,'inSert into log_query_stat(occ_time,q_id,total,response_time,gc_no) values(from_unixtime(%d),%d,%d,%d,%d)'),('*C498B459FC6FB60',30,'inSert ignore into dnf_restrict_info (category , restrict_code , restrict_str , reg_date) values(%d, %d, \'%s\', now())'),('*3E5F283A8C3D2C1',31,'seLect count(*) from charac_tower_rank where tower_index=%d and part_type=%d'),('*4BDD1A8E6B6297B',32,'seLect b.rank,a.tower_index, a.member_info_%d,a.stage_%d,a.play_time_%d from charac_tower_record a,charac_tower_rank b where b.tower_index=%d and b.tower_index=a.tower_index and (b.rank>5 and (b.rank%%%d)=0) and a.charac_no=b.charac_no and b.part_type=%d order by b.rank asc limit %d'),('*39636577CD2E623',33,'seLect b.rank,a.tower_index, a.member_info_%d,a.stage_%d,a.play_time_%d from charac_tower_record a,charac_tower_rank_top5 b where b.tower_index=%d and b.tower_index=a.tower_index and b.rank<=5 and a.charac_no=b.charac_no and b.part_type=%d order by b.rank asc limit %d'),('*8BC4C91D778EBE4',34,'upDate game_channel set gc_now=0,gc_ip=\'%s\',gc_port=%d,gc_max=%d,gc_game=%d,gc_channel=\'%s\',gc_ch_group=%d,gc_channeltype=\'%s\',gc_up_time=now(),gc_type=%d where gc_no=%d'),('*9F24D6FDD3CBB20',35,'inSert into dnf_dbq_log(occ_time,channel_no,dbq) values(NOW(),%d,%d)'),('*6F0167591240276',36,'upDate game_channel set gc_now=%d,gc_up_time=now(),gc_swordman_cnt=%d,gc_fighter_cnt=%d,gc_gunner_cnt=%d,gc_mage_cnt=%d,gc_priest_cnt=%d,gc_at_gunner_cnt=%d,gc_thief_cnt=%d,gc_hangame=%d,gc_nexon=%d where gc_no=%d'),('*6773E38D9FBFF0B',37,'inSert into log_game_channel(gc_up_time,gc_game,gc_no,gc_channel,gc_ch_group,gc_ip,gc_now,gc_new,gc_out) values(now(),%d,%d,\'%s\',%d,\'%s\',%d,%d,%d)'),('*7528CEC0129BDF7',38,'inSert into channel_lev_status(occ_time,channel_no,lev,occ_count) values(from_unixtime(%d),%d,%d,%d)');
/*!40000 ALTER TABLE `log_query_ref` ENABLE KEYS */;
